class AgentCubeError(Exception):
    """Base exception for AgentCube SDK."""
    pass


class CommandExecutionError(AgentCubeError):
    """Raised when a command execution returns a non-zero exit code."""
    def __init__(self, message: str, exit_code: int, stdout: str = "", stderr: str = ""):
        super().__init__(message)
        self.exit_code = exit_code
        self.stdout = stdout
        self.stderr = stderr


class SessionError(AgentCubeError):
    """Raised when there is an error with session management."""
    pass


class NotFoundError(AgentCubeError):

