package workloadmanager

import (
	"bytes"
	"context"
	"encoding/json"
	"errors"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/gin-gonic/gin"

	"github.com/anomalyco/agentcube/pkg/common/types"
	"github.com/anomalyco/agentcube/pkg/store"
)

type mockStore struct {
	sandboxes    map[string]*types.SandboxInfo
	pingErr      error
	storeErr     error
	updateErr    error
	deleteErr    error
	getErr       error
	listInactive []*types.SandboxInfo
	listExpired  []*types.SandboxInfo
}

func newMockStore() *mockStore {
	return &mockStore{
		sandboxes: make(map[string]*types.SandboxInfo),
	}
}

func (m *mockStore) Ping(ctx context.Context) error {
	return m.pingErr
}

func (m *mockStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	if m.getErr != nil {
		return nil, m.getErr
	}
	sandbox, ok := m.sandboxes[sessionID]
	if !ok {
		return nil, store.ErrSessionNotFound
	}
	return sandbox, nil
}

func (m *mockStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if m.storeErr != nil {
		return m.storeErr
	}
	m.sandboxes[sandbox.SessionID] = sandbox
	return nil
}

func (m *mockStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if m.updateErr != nil {
		return m.updateErr
	}
	m.sandboxes[sandbox.SessionID] = sandbox
	return nil
}

func (m *mockStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	if m.deleteErr != nil {
		return m.deleteErr
	}
	delete(m.sandboxes, sessionID)
	return nil
}

func (m *mockStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return m.listExpired, nil
}

func (m *mockStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return m.listInactive, nil
}

func (m *mockStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	return nil
}

func (m *mockStore) Close() error {
	return nil
}

type mockK8sClient struct {
	createErr    error
	deleteErr    error
	getErr       error
	podIP        string
	podName      string
	createdPods  map[string]bool
	deletedPods  map[string]bool
}

func newMockK8sClient() *mockK8sClient {
	return &mockK8sClient{
		createdPods: make(map[string]bool),
		deletedPods: make(map[string]bool),
		podName:    "test-pod-abc12345",
		podIP:      "10.0.0.1",
	}
}

func (m *mockK8sClient) CreateAgentRuntime(ctx context.Context, sandbox *types.SandboxInfo, template *types.SandboxTemplate, runtimeClassName string) (string, error) {
	if m.createErr != nil {
		return "", m.createErr
	}
	m.createdPods[sandbox.Name] = true
	if m.podName != "" {
		return m.podName, nil
	}
	return sandbox.Name + "-" + sandbox.SessionID[:8], nil
}

func (m *mockK8sClient) DeleteAgentRuntime(ctx context.Context, namespace, name string) error {
	if m.deleteErr != nil {
		return m.deleteErr
	}
	m.deletedPods[name] = true
	return nil
}

func (m *mockK8sClient) CreateCodeInterpreter(ctx context.Context, sandbox *types.SandboxInfo, template *types.SandboxTemplate, runtimeClassName string) (string, error) {
	if m.createErr != nil {
		return "", m.createErr
	}
	m.createdPods[sandbox.Name] = true
	if m.podName != "" {
		return m.podName, nil
	}
	return sandbox.Name + "-" + sandbox.SessionID[:8], nil
}

func (m *mockK8sClient) DeleteCodeInterpreter(ctx context.Context, namespace, name string) error {
	if m.deleteErr != nil {
		return m.deleteErr
	}
	m.deletedPods[name] = true
	return nil
}

func newTestServer(t *testing.T, store store.Store, k8sClient *K8sClient) *Server {
	t.Helper()
	gin.SetMode(gin.TestMode)

	cfg := NewConfig()
	return NewServer(cfg, k8sClient, store)
}

func TestConfig_Validate(t *testing.T) {
	tests := []struct {
		name    string
		cfg     *Config
		wantErr bool
	}{
		{
			name:    "valid config",
			cfg:     &Config{Port: 8080},
			wantErr: false,
		},
		{
			name:    "invalid port zero",
			cfg:     &Config{Port: 0},
			wantErr: true,
		},
		{
			name:    "invalid port negative",
			cfg:     &Config{Port: -1},
			wantErr: true,
		},
		{
			name:    "invalid port too high",
			cfg:     &Config{Port: 65536},
			wantErr: true,
		},
		{
			name:    "TLS enabled without cert",
			cfg:     &Config{Port: 8080, EnableTLS: true, TLSCert: "", TLSKey: "key.pem"},
			wantErr: true,
		},
		{
			name:    "TLS enabled without key",
			cfg:     &Config{Port: 8080, EnableTLS: true, TLSCert: "cert.pem", TLSKey: ""},
			wantErr: true,
		},
		{
			name:    "TLS enabled with both cert and key",
			cfg:     &Config{Port: 8080, EnableTLS: true, TLSCert: "cert.pem", TLSKey: "key.pem"},
			wantErr: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.cfg.Validate()
			if (err != nil) != tt.wantErr {
				t.Errorf("Validate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestHealthHandler(t *testing.T) {
	mockStore := newMockStore()
	srv := newTestServer(t, mockStore, nil)

	req := httptest.NewRequest("GET", "/health", nil)
	w := httptest.NewRecorder()

	srv.router.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Errorf("Health handler returned %d, want %d", w.Code, http.StatusOK)
	}

	var response map[string]interface{}
	if err := json.Unmarshal(w.Body.Bytes(), &response); err != nil {
		t.Fatalf("Failed to unmarshal response: %v", err)
	}

	if response["status"] != "ok" {
		t.Errorf("Status = %v, want ok", response["status"])
	}
}

func TestHealthHandler_StoreUnavailable(t *testing.T) {
