	srv.router.ServeHTTP(w, req)

	if w.Code != http.StatusServiceUnavailable {
		t.Errorf("Health handler returned %d, want %d", w.Code, http.StatusServiceUnavailable)
	}
}

func TestCreateAgentRuntime_Success(t *testing.T) {
	mockStore := newMockStore()
	mockK8s := newMockK8sClient()
	srv := newTestServer(t, mockStore, &K8sClient{})

	body := `{"name": "test-agent", "namespace": "default"}`
	req := httptest.NewRequest("POST", "/v1/agent-runtime", bytes.NewBufferString(body))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()

	srv.router.ServeHTTP(w, req)

	if w.Code != http.StatusCreated {
		t.Errorf("Create handler returned %d, want %d. Body: %s", w.Code, http.StatusCreated, w.Body.String())
	}

	var response CreateSandboxResponse
	if err := json.Unmarshal(w.Body.Bytes(), &response); err != nil {
		t.Fatalf("Failed to unmarshal response: %v", err)
	}

	if response.SessionID == "" {
		t.Error("SessionID should not be empty")
	}
	if response.Name != "test-agent" {
		t.Errorf("Name = %v, want test-agent", response.Name)
	}
	if response.Namespace != "default" {
		t.Errorf("Namespace = %v, want default", response.Namespace)
	}
	if response.Status != "creating" {
		t.Errorf("Status = %v, want creating", response.Status)
	}
}

