func TestBuildEntryPoints(t *testing.T) {
	srv := &Server{}

	tests := []struct {
		name     string
		sandbox  *types.SandboxInfo
		expected int
	}{
		{
			name: "nil labels",
			sandbox: &types.SandboxInfo{
				SessionID: "test",
			},
			expected: 0,
		},
		{
			name: "empty labels",
			sandbox: &types.SandboxInfo{
				SessionID: "test",
				Labels:    map[string]string{},
			},
			expected: 0,
		},
		{
			name: "with ports annotation",
			sandbox: &types.SandboxInfo{
				SessionID: "test",
				Labels:    map[string]string{"app": "test"},
				Annotations: map[string]string{
					"ports": `[{"name":"http","port":8080,"protocol":"HTTP"}]`,
				},
			},
			expected: 1,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			entryPoints := srv.buildEntryPoints(tt.sandbox)
			if len(entryPoints) != tt.expected {
				t.Errorf("buildEntryPoints() returned %d entries, want %d", len(entryPoints), tt.expected)
			}
		})
	}
}

