func TestServer_Routes(t *testing.T) {
	mockStore := newMockStore()
	srv := newTestServer(t, mockStore, &K8sClient{})

	routes := srv.router.Routes()

	routeMap := make(map[string]bool)
	for _, route := range routes {
		key := route.Method + " " + route.Path
		routeMap[key] = true
	}

	expectedRoutes := []string{
		"GET /health",
		"POST /v1/agent-runtime",
		"DELETE /v1/agent-runtime/sessions/:sessionId",
		"POST /v1/code-interpreter",
		"DELETE /v1/code-interpreter/sessions/:sessionId",
	}

	for _, expected := range expectedRoutes {
		if !routeMap[expected] {
			t.Errorf("Expected route %s not found", expected)
		}
	}
}

