package router

import (
	"context"
	"encoding/json"
	"errors"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"

	"github.com/gin-gonic/gin"

	"github.com/anomalyco/agentcube/pkg/common/types"
	"github.com/anomalyco/agentcube/pkg/store"
)

type mockRouterStore struct {
	sandboxes    map[string]*types.SandboxInfo
	pingErr      error
	getErr       error
	updateErr    error
	deleteErr    error
}

func newMockRouterStore() *mockRouterStore {
	return &mockRouterStore{
		sandboxes: make(map[string]*types.SandboxInfo),
	}
}

func (m *mockRouterStore) Ping(ctx context.Context) error {
	return m.pingErr
}

func (m *mockRouterStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	if m.getErr != nil {
		return nil, m.getErr
	}
	sandbox, ok := m.sandboxes[sessionID]
	if !ok {
		return nil, store.ErrSessionNotFound
	}
	return sandbox, nil
}

func (m *mockRouterStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	m.sandboxes[sandbox.SessionID] = sandbox
	return nil
}

func (m *mockRouterStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if m.updateErr != nil {
		return m.updateErr
	}
	m.sandboxes[sandbox.SessionID] = sandbox
	return nil
}

func (m *mockRouterStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	if m.deleteErr != nil {
		return m.deleteErr
	}
	delete(m.sandboxes, sessionID)
	return nil
}

func (m *mockRouterStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return nil, nil
}

func (m *mockRouterStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return nil, nil
}

func (m *mockRouterStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	return nil
}

func (m *mockRouterStore) Close() error {
	return nil
}

func TestConfig_Validate(t *testing.T) {
	tests := []struct {
