func TestProxy_MapProxyError(t *testing.T) {
	proxy := NewProxy()

	tests := []struct {
		name         string
		err          error
		expectedCode int
		expectedMsg  string
	}{
		{
			name:         "connection refused",
			err:          errors.New("dial tcp 10.0.0.1:8080: connection refused"),
			expectedCode: http.StatusBadGateway,
			expectedMsg:  ErrConnectionRefused.Error(),
		},
		{
			name:         "timeout",
			err:          &netTimeoutError{},
			expectedCode: http.StatusGatewayTimeout,
			expectedMsg:  ErrTimeout.Error(),
		},
		{
			name:         "no such host",
			err:          errors.New("dial tcp: lookup unknown: no such host"),
			expectedCode: http.StatusBadGateway,
			expectedMsg:  "host not found",
		},
		{
			name:         "connection reset",
			err:          errors.New("read tcp: connection reset by peer"),
			expectedCode: http.StatusBadGateway,
			expectedMsg:  "connection reset",
		},
		{
			name:         "broken pipe",
			err:          errors.New("write tcp: broken pipe"),
			expectedCode: http.StatusBadGateway,
			expectedMsg:  "broken pipe",
		},
		{
			name:         "i/o timeout",
			err:          errors.New("read tcp: i/o timeout"),
			expectedCode: http.StatusGatewayTimeout,
			expectedMsg:  ErrTimeout.Error(),
		},
		{
			name:         "context deadline exceeded",
			err:          errors.New("context deadline exceeded"),
			expectedCode: http.StatusGatewayTimeout,
			expectedMsg:  ErrTimeout.Error(),
		},
		{
			name:         "context canceled",
			err:          errors.New("context canceled"),
			expectedCode: http.StatusGatewayTimeout,
			expectedMsg:  "request canceled",
		},
		{
			name:         "unknown error",
			err:          errors.New("unknown error"),
			expectedCode: http.StatusBadGateway,
			expectedMsg:  "upstream error",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			code, msg := proxy.mapProxyError(tt.err)
			if code != tt.expectedCode {
				t.Errorf("mapProxyError() code = %v, want %v", code, tt.expectedCode)
			}
			if msg != tt.expectedMsg {
				t.Errorf("mapProxyError() msg = %v, want %v", msg, tt.expectedMsg)
			}
		})
	}
}

