	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/golang-jwt/jwt/v5"
)

func generateTestRSAKey(t *testing.T) *rsa.PrivateKey {
	t.Helper()
	key, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		t.Fatalf("Failed to generate RSA key: %v", err)
	}
	return key
}

func TestNewJWTManager(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	jwtMgr, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("NewJWTManager() error = %v", err)
	}

	if jwtMgr == nil {
		t.Fatal("NewJWTManager() returned nil")
	}

	if _, err := os.Stat(keyFile); os.IsNotExist(err) {
		t.Error("Key file was not created")
	}
}

func TestNewJWTManager_LoadExistingKey(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	jwtMgr1, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("First NewJWTManager() error = %v", err)
	}

	jwtMgr2, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("Second NewJWTManager() error = %v", err)
	}

	if jwtMgr1.GetKeyID() != jwtMgr2.GetKeyID() {
		t.Error("Key IDs should be the same when loading existing key")
	}
}

func TestJWTManager_GenerateToken(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	jwtMgr, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("NewJWTManager() error = %v", err)
	}

	session := &SessionInfo{
		SessionID: "test-session-id",
		Name:      "test-sandbox",
		Namespace: "default",
		Kind:      "agent-runtime",
	}

	token, err := jwtMgr.GenerateToken(session)
	if err != nil {
		t.Fatalf("GenerateToken() error = %v", err)
	}

	if token == "" {
		t.Error("GenerateToken() returned empty token")
	}
}

func TestJWTManager_GenerateTokenForSandbox(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	jwtMgr, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("NewJWTManager() error = %v", err)
	}

	sandbox := &SessionInfo{
		SessionID: "test-session-id",
		Name:      "test-sandbox",
		Namespace: "default",
		Kind:      "code-interpreter",
	}

	token, err := jwtMgr.GenerateTokenForSandbox(sandbox)
	if err != nil {
		t.Fatalf("GenerateTokenForSandbox() error = %v", err)
	}

	if token == "" {
		t.Error("GenerateTokenForSandbox() returned empty token")
	}
}

func TestJWTManager_SignRequest(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	jwtMgr, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("NewJWTManager() error = %v", err)
	}

	session := &SessionInfo{
		SessionID: "test-session-id",
		Name:      "test-sandbox",
		Namespace: "default",
		Kind:      "agent-runtime",
	}

	req := httptest.NewRequest("GET", "/test", nil)

	if err := jwtMgr.SignRequest(req, session); err != nil {
		t.Fatalf("SignRequest() error = %v", err)
	}

	authHeader := req.Header.Get("Authorization")
	if authHeader == "" {
		t.Error("Authorization header should be set")
	}
	if len(authHeader) < 7 || authHeader[:7] != "Bearer " {
		t.Errorf("Authorization header = %v, want 'Bearer <token>'", authHeader)
	}
}

func TestJWTManager_VerifyToken(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	jwtMgr, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("NewJWTManager() error = %v", err)
	}

	session := &SessionInfo{
		SessionID: "test-session-id",
		Name:      "test-sandbox",
		Namespace: "default",
		Kind:      "agent-runtime",
	}

	token, err := jwtMgr.GenerateToken(session)
	if err != nil {
		t.Fatalf("GenerateToken() error = %v", err)
	}

	publicKey := jwtMgr.GetPublicKey()

	parsedToken, err := jwt.ParseWithClaims(token, &SandboxClaims{}, func(token *jwt.Token) (interface{}, error) {
		return publicKey, nil
	})

	if err != nil {
		t.Fatalf("Failed to parse token: %v", err)
	}

	if !parsedToken.Valid {
		t.Error("Token should be valid")
	}

	claims, ok := parsedToken.Claims.(*SandboxClaims)
	if !ok {
		t.Fatal("Failed to cast claims")
	}

	if claims.SessionID != session.SessionID {
		t.Errorf("SessionID = %v, want %v", claims.SessionID, session.SessionID)
	}
	if claims.Name != session.Name {
		t.Errorf("Name = %v, want %v", claims.Name, session.Name)
	}
	if claims.Namespace != session.Namespace {
		t.Errorf("Namespace = %v, want %v", claims.Namespace, session.Namespace)
	}
	if claims.Kind != session.Kind {
		t.Errorf("Kind = %v, want %v", claims.Kind, session.Kind)
	}
}

func TestJWTManager_ExpiredToken(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	privateKey := generateTestRSAKey(t)

	keyBytes := x509.MarshalPKCS1PrivateKey(privateKey)
	pemBlock := &pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: keyBytes,
	}
	pemData := pem.EncodeToMemory(pemBlock)

	if err := os.WriteFile(keyFile, pemData, 0600); err != nil {
		t.Fatalf("Failed to write key file: %v", err)
	}

	jwtMgr, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("NewJWTManager() error = %v", err)
	}

	claims := &SandboxClaims{
		SessionID: "test-session-id",
		Name:      "test-sandbox",
		Namespace: "default",
		Kind:      "agent-runtime",
		RegisteredClaims: jwt.RegisteredClaims{
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(-1 * time.Hour)),
			IssuedAt:  jwt.NewNumericDate(time.Now().Add(-2 * time.Hour)),
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	tokenString, err := token.SignedString(privateKey)
	if err != nil {
		t.Fatalf("Failed to sign token: %v", err)
	}

	publicKey := jwtMgr.GetPublicKey()

	_, err = jwt.ParseWithClaims(tokenString, &SandboxClaims{}, func(token *jwt.Token) (interface{}, error) {
		return publicKey, nil
	})

	if err == nil {
		t.Error("Expected error for expired token")
	}
}

func TestJWTManager_GetPublicKeyPEM(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	jwtMgr, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("NewJWTManager() error = %v", err)
	}

	pemStr, err := jwtMgr.GetPublicKeyPEM()
	if err != nil {
		t.Fatalf("GetPublicKeyPEM() error = %v", err)
	}

	if pemStr == "" {
		t.Error("GetPublicKeyPEM() returned empty string")
	}

	block, _ := pem.Decode([]byte(pemStr))
	if block == nil {
		t.Fatal("Failed to decode PEM block")
	}
	if block.Type != "PUBLIC KEY" {
		t.Errorf("PEM block type = %v, want 'PUBLIC KEY'", block.Type)
	}
}

func TestJWTManager_RotateKey(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	jwtMgr, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("NewJWTManager() error = %v", err)
	}

	originalKeyID := jwtMgr.GetKeyID()

	if err := jwtMgr.RotateKey(); err != nil {
		t.Fatalf("RotateKey() error = %v", err)
	}

	newKeyID := jwtMgr.GetKeyID()

	if originalKeyID == newKeyID {
		t.Error("Key ID should change after rotation")
	}
}

func TestJWTManager_SignSandboxClaim(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	jwtMgr, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("NewJWTManager() error = %v", err)
	}

	sandbox := &SessionInfo{
		SessionID: "test-session-id",
		Name:      "test-sandbox",
		Namespace: "default",
		Kind:      "agent-runtime",
	}

	token, err := jwtMgr.SignSandboxClaim(sandbox, "Sandbox")
	if err != nil {
		t.Fatalf("SignSandboxClaim() error = %v", err)
	}

	if token == "" {
		t.Error("SignSandboxClaim() returned empty token")
	}
}

func TestJWTManager_Constants(t *testing.T) {
	if DefaultKeySize != 2048 {
		t.Errorf("DefaultKeySize = %d, want 2048", DefaultKeySize)
	}
	if DefaultKeyDir != "/var/run/agentcube" {
		t.Errorf("DefaultKeyDir = %v, want /var/run/agentcube", DefaultKeyDir)
	}
	if DefaultPrivateKeyFile != "jwt-private-key.pem" {
		t.Errorf("DefaultPrivateKeyFile = %v, want jwt-private-key.pem", DefaultPrivateKeyFile)
	}
	if KeyIDHeader != "kid" {
		t.Errorf("KeyIDHeader = %v, want kid", KeyIDHeader)
	}
	if IssuerClaim != "agentcube-router" {
		t.Errorf("IssuerClaim = %v, want agentcube-router", IssuerClaim)
	}
	if AudienceClaim != "agentcube-sandbox" {
		t.Errorf("AudienceClaim = %v, want agentcube-sandbox", AudienceClaim)
	}
	if DefaultTokenDuration != 5*time.Minute {
		t.Errorf("DefaultTokenDuration = %v, want 5m", DefaultTokenDuration)
	}
}

func TestGenerateKeyID(t *testing.T) {
	key := generateTestRSAKey(t)

	keyID := generateKeyID(key)

	if keyID == "" {
		t.Error("generateKeyID() returned empty string")
	}

	if len(keyID) > 16 {
		t.Errorf("generateKeyID() returned string longer than 16 chars: %s", keyID)
	}
}

func TestLoadOrCreateKey_InvalidDirectory(t *testing.T) {
	keyFile := "/nonexistent/directory/test-key.pem"

	_, _, err := LoadOrCreateKey(keyFile)
	if err == nil {
		t.Error("LoadOrCreateKey() should fail for non-existent directory")
	}
}

func TestJWTManager_HS256Rejected(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	jwtMgr, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("NewJWTManager() error = %v", err)
	}

	hs256Token := "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiJ0ZXN0In0.test"

	publicKey := jwtMgr.GetPublicKey()

	_, err = jwt.ParseWithClaims(hs256Token, &SandboxClaims{}, func(token *jwt.Token) (interface{}, error) {
		if _, ok := token.Method.(*jwt.SigningMethodHMAC); ok {
			return nil, jwt.ErrSignatureInvalid
		}
		return publicKey, nil
	})

	if err == nil {
		t.Error("HS256 token should be rejected")
	}
}

func TestJWTManager_TokenClaims(t *testing.T) {
	tmpDir := t.TempDir()
	keyFile := filepath.Join(tmpDir, "test-key.pem")

	jwtMgr, err := NewJWTManager(keyFile)
	if err != nil {
		t.Fatalf("NewJWTManager() error = %v", err)
	}

	session := &SessionInfo{
		SessionID: "session-123",
		Name:      "my-sandbox",
		Namespace: "production",
		Kind:      "code-interpreter",
	}

	token, err := jwtMgr.GenerateToken(session)
	if err != nil {
		t.Fatalf("GenerateToken() error = %v", err)
	}

	publicKey := jwtMgr.GetPublicKey()

	parsedToken, err := jwt.ParseWithClaims(token, &SandboxClaims{}, func(token *jwt.Token) (interface{}, error) {
		return publicKey, nil
	})

	if err != nil {
		t.Fatalf("Failed to parse token: %v", err)
	}

	claims := parsedToken.Claims.(*SandboxClaims)

	if claims.Issuer != IssuerClaim {
		t.Errorf("Issuer = %v, want %v", claims.Issuer, IssuerClaim)
	}
	if claims.Subject != session.SessionID {
		t.Errorf("Subject = %v, want %v", claims.Subject, session.SessionID)
	}
	if len(claims.Audience) != 1 || claims.Audience[0] != AudienceClaim {
		t.Errorf("Audience = %v, want [%v]", claims.Audience, AudienceClaim)
	}
	if claims.ExpiresAt == nil {
		t.Error("ExpiresAt should not be nil")
	}
	if claims.IssuedAt == nil {
		t.Error("IssuedAt should not be nil")
	}
	if claims.NotBefore == nil {
		t.Error("NotBefore should not be nil")
	}
	if claims.ID == "" {
		t.Error("ID should not be empty")
	}
}

