package agentd

import (
	"testing"
	"time"

	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

func TestConfig_Validate(t *testing.T) {
	tests := []struct {
		name    string
		cfg     *Config
		wantErr bool
	}{
		{
			name:    "valid config",
			cfg:     &Config{ExpiryTimeout: 15 * time.Minute},
			wantErr: false,
		},
		{
			name:    "zero expiry timeout",
			cfg:     &Config{ExpiryTimeout: 0},
			wantErr: true,
		},
		{
			name:    "negative expiry timeout",
			cfg:     &Config{ExpiryTimeout: -1 * time.Minute},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.cfg.Validate()
			if (err != nil) != tt.wantErr {
				t.Errorf("Validate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestNewConfig(t *testing.T) {
	cfg := NewConfig()

	if cfg.ExpiryTimeout != DefaultExpiryTimeout {
		t.Errorf("ExpiryTimeout = %v, want %v", cfg.ExpiryTimeout, DefaultExpiryTimeout)
	}
}

func TestSandbox_IsExpired(t *testing.T) {
	tests := []struct {
		name          string
		sandbox       *Sandbox
		expiryTimeout time.Duration
		expected      bool
	}{
		{
			name: "not expired - recent activity",
			sandbox: &Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					Annotations: map[string]string{
						LastActivityAnnotation: time.Now().Add(-5 * time.Minute).Format(time.RFC3339),
					},
				},
			},
			expiryTimeout: 15 * time.Minute,
			expected:      false,
		},
		{
			name: "expired - old activity",
			sandbox: &Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					Annotations: map[string]string{
						LastActivityAnnotation: time.Now().Add(-30 * time.Minute).Format(time.RFC3339),
					},
				},
			},
			expiryTimeout: 15 * time.Minute,
			expected:      true,
		},
		{
			name: "not expired - no activity annotation",
			sandbox: &Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					CreationTimestamp: metav1.Now(),
				},
			},
			expiryTimeout: 15 * time.Minute,
			expected:      false,
		},
		{
			name: "expired - old creation time",
			sandbox: &Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					CreationTimestamp: metav1.NewTime(time.Now().Add(-30 * time.Minute)),
				},
			},
			expiryTimeout: 15 * time.Minute,
			expected:      true,
		},
		{
			name: "invalid timestamp format",
			sandbox: &Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					Annotations: map[string]string{
						LastActivityAnnotation: "invalid-timestamp",
					},
					CreationTimestamp: metav1.Now(),
				},
			},
			expiryTimeout: 15 * time.Minute,
			expected:      false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctrl := &Controller{
				expiryTimeout: tt.expiryTimeout,
			}
			result := ctrl.isExpired(tt.sandbox)
			if result != tt.expected {
				t.Errorf("isExpired() = %v, want %v", result, tt.expected)
			}
		})
	}
}

func TestController_CalculateRequeueAfter(t *testing.T) {
	tests := []struct {
		name          string
		sandbox       *Sandbox
		expiryTimeout time.Duration
		minExpected   time.Duration
		maxExpected   time.Duration
	}{
		{
			name: "with recent activity",
			sandbox: &Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					Annotations: map[string]string{
						LastActivityAnnotation: time.Now().Add(-5 * time.Minute).Format(time.RFC3339),
					},
				},
			},
			expiryTimeout: 15 * time.Minute,
			minExpected:   5 * time.Minute,
			maxExpected:   15 * time.Minute,
		},
		{
			name: "no activity annotation",
			sandbox: &Sandbox{
				ObjectMeta: metav1.ObjectMeta{
					CreationTimestamp: metav1.Now(),
				},
			},
			expiryTimeout: 15 * time.Minute,
			minExpected:   1 * time.Minute,
			maxExpected:   15 * time.Minute,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctrl := &Controller{
				expiryTimeout: tt.expiryTimeout,
			}
			result := ctrl.calculateRequeueAfter(tt.sandbox)
			if result < tt.minExpected {
				t.Errorf("calculateRequeueAfter() = %v, want at least %v", result, tt.minExpected)
			}
			if result > tt.maxExpected {
				t.Errorf("calculateRequeueAfter() = %v, want at most %v", result, tt.maxExpected)
			}
		})
	}
}

func TestConstants(t *testing.T) {
	if LastActivityAnnotation != "agentcube.io/last-activity" {
		t.Errorf("LastActivityAnnotation = %v, want agentcube.io/last-activity", LastActivityAnnotation)
	}
	if CreatedAtAnnotation != "agentcube.io/created-at" {
		t.Errorf("CreatedAtAnnotation = %v, want agentcube.io/created-at", CreatedAtAnnotation)
	}
	if ExpiresAtAnnotation != "agentcube.io/expires-at" {
		t.Errorf("ExpiresAtAnnotation = %v, want agentcube.io/expires-at", ExpiresAtAnnotation)
	}
	if SessionIDLabel != "agentcube.io/session-id" {
		t.Errorf("SessionIDLabel = %v, want agentcube.io/session-id", SessionIDLabel)
	}
	if DefaultExpiryTimeout != 15*time.Minute {
		t.Errorf("DefaultExpiryTimeout = %v, want 15m", DefaultExpiryTimeout)
	}
	if DefaultRequeueAfter != 1*time.Minute {
		t.Errorf("DefaultRequeueAfter = %v, want 1m", DefaultRequeueAfter)
	}
}

func TestSandbox_DeepCopy(t *testing.T) {
	original := &Sandbox{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-sandbox",
			Namespace: "default",
			Labels: map[string]string{
				"app": "test",
			},
			Annotations: map[string]string{
				LastActivityAnnotation: time.Now().Format(time.RFC3339),
			},
		},
		Spec: SandboxSpec{
			Template: TemplateSpec{
				Spec: PodSpec{
					Containers: []Container{
						{Name: "main", Image: "busybox"},
					},
				},
			},
		},
		Status: SandboxStatus{
			Phase: "Running",
			PodIP: "10.0.0.1",
		},
	}

	copy := original.DeepCopy()

	if copy.Name != original.Name {
		t.Errorf("Name = %v, want %v", copy.Name, original.Name)
	}
	if copy.Namespace != original.Namespace {
		t.Errorf("Namespace = %v, want %v", copy.Namespace, original.Namespace)
	}
	if len(copy.Labels) != len(original.Labels) {
		t.Errorf("Labels length = %v, want %v", len(copy.Labels), len(original.Labels))
	}
	if len(copy.Annotations) != len(original.Annotations) {
		t.Errorf("Annotations length = %v, want %v", len(copy.Annotations), len(original.Annotations))
	}
	if len(copy.Spec.Template.Spec.Containers) != len(original.Spec.Template.Spec.Containers) {
		t.Errorf("Containers length = %v, want %v", len(copy.Spec.Template.Spec.Containers), len(original.Spec.Template.Spec.Containers))
	}
	if copy.Status.Phase != original.Status.Phase {
		t.Errorf("Phase = %v, want %v", copy.Status.Phase, original.Status.Phase)
	}

	copy.Labels["new"] = "value"
	if _, exists := original.Labels["new"]; exists {
		t.Error("Modifying copy should not affect original")
	}
}

func TestSandboxList_DeepCopy(t *testing.T) {
	original := &SandboxList{
		Items: []Sandbox{
			{ObjectMeta: metav1.ObjectMeta{Name: "sandbox-1"}},
			{ObjectMeta: metav1.ObjectMeta{Name: "sandbox-2"}},
		},
	}

	copy := original.DeepCopy()

	if len(copy.Items) != len(original.Items) {
		t.Errorf("Items length = %v, want %v", len(copy.Items), len(original.Items))
	}

	copy.Items[0].Name = "modified"
	if original.Items[0].Name == "modified" {
		t.Error("Modifying copy should not affect original")
	}
}

func TestConvertToSandboxInfo(t *testing.T) {
	now := time.Now().UTC().Truncate(time.Second)

	sandbox := &Sandbox{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-sandbox",
			Namespace: "default",
			UID:       "test-uid",
			Labels: map[string]string{
				"app": "test",
			},
			Annotations: map[string]string{
				SessionIDLabel:         "test-session-id",
				LastActivityAnnotation: now.Format(time.RFC3339),
				ExpiresAtAnnotation:    now.Add(1 * time.Hour).Format(time.RFC3339),
			},
			CreationTimestamp: metav1.NewTime(now),
		},
		Status: SandboxStatus{
			PodIP: "10.0.0.1",
		},
	}

	info := ConvertToSandboxInfo(sandbox)

	if info.SessionID != "test-session-id" {
		t.Errorf("SessionID = %v, want test-session-id", info.SessionID)
	}
	if info.Name != "test-sandbox" {
		t.Errorf("Name = %v, want test-sandbox", info.Name)
	}
	if info.Namespace != "default" {
		t.Errorf("Namespace = %v, want default", info.Namespace)
	}
	if info.PodIP != "10.0.0.1" {
		t.Errorf("PodIP = %v, want 10.0.0.1", info.PodIP)
	}
	if len(info.Labels) != 1 {
		t.Errorf("Labels length = %v, want 1", len(info.Labels))
	}
}

func TestConvertToSandboxInfo_NoSessionID(t *testing.T) {
	sandbox := &Sandbox{
		ObjectMeta: metav1.ObjectMeta{
			Name:              "test-sandbox",
			Namespace:         "default",
			UID:               "test-uid",
			CreationTimestamp: metav1.Now(),
		},
	}

	info := ConvertToSandboxInfo(sandbox)

	if info.SessionID != "test-uid" {
		t.Errorf("SessionID = %v, want test-uid", info.SessionID)
	}
}

func TestController_IsExpired_EdgeCases(t *testing.T) {
	ctrl := &Controller{
		expiryTimeout: 15 * time.Minute,
	}

	t.Run("nil annotations", func(t *testing.T) {
		sandbox := &Sandbox{
			ObjectMeta: metav1.ObjectMeta{
				CreationTimestamp: metav1.Now(),
			},
		}
		if ctrl.isExpired(sandbox) {
			t.Error("Should not be expired with recent creation time")
		}
	})

	t.Run("empty annotations", func(t *testing.T) {
		sandbox := &Sandbox{
			ObjectMeta: metav1.ObjectMeta{
				Annotations:      map[string]string{},
				CreationTimestamp: metav1.Now(),
			},
		}
		if ctrl.isExpired(sandbox) {
			t.Error("Should not be expired with recent creation time")
		}
	})

	t.Run("exactly at boundary", func(t *testing.T) {
		sandbox := &Sandbox{
			ObjectMeta: metav1.ObjectMeta{
				Annotations: map[string]string{
					LastActivityAnnotation: time.Now().Add(-15 * time.Minute).Format(time.RFC3339),
				},
			},
		}
		result := ctrl.isExpired(sandbox)
		if result {
			t.Error("At exact boundary, should not be expired yet")
		}
	})
}

