"""Tests for AgentCube Python SDK CodeInterpreterClient."""

from unittest.mock import Mock, patch, MagicMock
import pytest
import requests

from agentcube.client import CodeInterpreterClient
from agentcube.exceptions import SessionError


class TestCodeInterpreterClient:
    def test_init_with_urls(self):
        with patch.object(CodeInterpreterClient, '_ensure_session'):
            client = CodeInterpreterClient(
                control_plane_url="http://localhost:8080",
                data_plane_url="http://localhost:8081",
            )
            assert client._control_plane_url == "http://localhost:8080"
            assert client._data_plane_url == "http://localhost:8081"

    def test_init_with_auth_token(self):
        with patch.object(CodeInterpreterClient, '_ensure_session'):
            client = CodeInterpreterClient(
                control_plane_url="http://localhost:8080",
                data_plane_url="http://localhost:8081",
                auth_token="test-token",
            )
            assert client._auth_token == "test-token"

    def test_context_manager(self):
        with patch.object(CodeInterpreterClient, '_ensure_session'):
            with CodeInterpreterClient(
                control_plane_url="http://localhost:8080",
                data_plane_url="http://localhost:8081",
            ) as client:
                assert client is not None

    def test_context_manager_calls_close(self):
        mock_close = Mock()
        with patch.object(CodeInterpreterClient, '_ensure_session'):
            with CodeInterpreterClient(
                control_plane_url="http://localhost:8080",
                data_plane_url="http://localhost:8081",
            ) as client:
                client.close = mock_close

    @patch('agentcube.client.ControlPlaneClient')
    @patch('agentcube.client.CodeInterpreterDataPlaneClient')
    def test_ensure_session_creates_session(self, mock_dp_client, mock_cp_client):
        mock_cp_instance = Mock()
        mock_cp_instance.create_session.return_value = {"session_id": "test-session"}
        mock_cp_client.return_value = mock_cp_instance

        client = CodeInterpreterClient(
            control_plane_url="http://localhost:8080",
            data_plane_url="http://localhost:8081",
        )
        client._ensure_session()

        assert client._session_id == "test-session"
        mock_cp_instance.create_session.assert_called_once()

    @patch('agentcube.client.ControlPlaneClient')
    def test_ensure_session_no_session_id_raises(self, mock_cp_client):
        mock_cp_instance = Mock()
        mock_cp_instance.create_session.return_value = {}
        mock_cp_client.return_value = mock_cp_instance

        client = CodeInterpreterClient(
            control_plane_url="http://localhost:8080",
            data_plane_url="http://localhost:8081",
        )
        with pytest.raises(SessionError):
            client._ensure_session()

    def test_close_deletes_session(self):
        client = CodeInterpreterClient(
            control_plane_url="http://localhost:8080",
            data_plane_url="http://localhost:8081",
        )
        client._session_id = "test-session"
        client._control_plane = Mock()
        client._data_plane = Mock()

        client.close()

        client._control_plane.delete_session.assert_called_once_with("test-session")
        client._data_plane.close.assert_called_once()
        client._control_plane.close.assert_called_once()

    def test_close_without_session(self):
        client = CodeInterpreterClient(
            control_plane_url="http://localhost:8080",
            data_plane_url="http://localhost:8081",
        )
        client._control_plane = Mock()
        client._data_plane = Mock()

        client.close()

        client._control_plane.delete_session.assert_not_called()

    def test_close_handles_exception(self):
        client = CodeInterpreterClient(
            control_plane_url="http://localhost:8080",
            data_plane_url="http://localhost:8081",
        )
        client._session_id = "test-session"
        client._control_plane = Mock()
        client._control_plane.delete_session.side_effect = Exception("error")
        client._data_plane = Mock()

        client.close()

    @patch('agentcube.client.ControlPlaneClient')
    @patch('agentcube.client.CodeInterpreterDataPlaneClient')
    def test_execute_command(self, mock_dp_client, mock_cp_client):
        mock_cp_instance = Mock()
        mock_cp_instance.create_session.return_value = {"session_id": "test-session"}
        mock_cp_client.return_value = mock_cp_instance

        mock_dp_instance = Mock()
        mock_dp_instance.execute_command.return_value = {"exit_code": 0, "stdout": "output"}
        mock_dp_client.return_value = mock_dp_instance

        client = CodeInterpreterClient(
            control_plane_url="http://localhost:8080",
            data_plane_url="http://localhost:8081",
        )
        result = client.execute_command("echo hello")

        assert result["exit_code"] == 0

    @patch('agentcube.client.ControlPlaneClient')
    @patch('agentcube.client.CodeInterpreterDataPlaneClient')
    def test_run_code(self, mock_dp_client, mock_cp_client):
        mock_cp_instance = Mock()
        mock_cp_instance.create_session.return_value = {"session_id": "test-session"}
        mock_cp_client.return_value = mock_cp_instance

        mock_dp_instance = Mock()
        mock_dp_instance.run_code.return_value = {"exit_code": 0, "stdout": "output"}
        mock_dp_client.return_value = mock_dp_instance

        client = CodeInterpreterClient(
            control_plane_url="http://localhost:8080",
            data_plane_url="http://localhost:8081",
        )
        result = client.run_code('print("hello")')

        mock_dp_instance.run_code.assert_called_once_with('print("hello")', language="python")

    @patch('agentcube.client.ControlPlaneClient')
    @patch('agentcube.client.CodeInterpreterDataPlaneClient')
    def test_write_file(self, mock_dp_client, mock_cp_client):
        mock_cp_instance = Mock()
        mock_cp_instance.create_session.return_value = {"session_id": "test-session"}
        mock_cp_client.return_value = mock_cp_instance

        mock_dp_instance = Mock()
        mock_dp_instance.write_file.return_value = {"path": "test.txt"}
        mock_dp_client.return_value = mock_dp_instance

        client = CodeInterpreterClient(
            control_plane_url="http://localhost:8080",
            data_plane_url="http://localhost:8081",
        )
        result = client.write_file("test.txt", "content")

        mock_dp_instance.write_file.assert_called_once_with("test.txt", "content")

    @patch('agentcube.client.ControlPlaneClient')
    @patch('agentcube.client.CodeInterpreterDataPlaneClient')
    def test_upload_file(self, mock_dp_client, mock_cp_client):
        mock_cp_instance = Mock()
        mock_cp_instance.create_session.return_value = {"session_id": "test-session"}
        mock_cp_client.return_value = mock_cp_instance

        mock_dp_instance = Mock()
        mock_dp_instance.upload_file.return_value = {"path": "uploaded.txt"}
        mock_dp_client.return_value = mock_dp_instance

        client = CodeInterpreterClient(
            control_plane_url="http://localhost:8080",
            data_plane_url="http://localhost:8081",
        )
        result = client.upload_file("/local/file.txt")

        mock_dp_instance.upload_file.assert_called_once_with("/local/file.txt", remote_path=None)

    @patch('agentcube.client.ControlPlaneClient')
    @patch('agentcube.client.CodeInterpreterDataPlaneClient')
    def test_download_file(self, mock_dp_client, mock_cp_client):
        mock_cp_instance = Mock()
        mock_cp_instance.create_session.return_value = {"session_id": "test-session"}
        mock_cp_client.return_value = mock_cp_instance

        mock_dp_instance = Mock()
        mock_dp_instance.download_file.return_value = b"file content"
        mock_dp_client.return_value = mock_dp_instance

        client = CodeInterpreterClient(
            control_plane_url="http://localhost:8080",
            data_plane_url="http://localhost:8081",
        )
        content = client.download_file("test.txt")

        assert content == b"file content"

    @patch('agentcube.client.ControlPlaneClient')
    @patch('agentcube.client.CodeInterpreterDataPlaneClient')
    def test_list_files(self, mock_dp_client, mock_cp_client):
        mock_cp_instance = Mock()
        mock_cp_instance.create_session.return_value = {"session_id": "test-session"}
        mock_cp_client.return_value = mock_cp_instance

        mock_dp_instance = Mock()
        mock_dp_instance.list_files.return_value = [{"name": "file.txt"}]
        mock_dp_client.return_value = mock_dp_instance

        client = CodeInterpreterClient(
            control_plane_url="http://localhost:8080",
            data_plane_url="http://localhost:8081",
        )
        files = client.list_files("/")

        assert len(files) == 1

